query:
CREATE CONSTRAINT user_id IF NOT EXISTS
FOR (u:User) REQUIRE u.userId IS UNIQUE;

CREATE CONSTRAINT movie_id IF NOT EXISTS
FOR (m:Movie) REQUIRE m.movieId IS UNIQUE;

CREATE CONSTRAINT genre_name IF NOT EXISTS
FOR (g:Genre) REQUIRE g.name IS UNIQUE;

LOAD CSV WITH HEADERS FROM 'file:///movies_node.csv' AS row MERGE (m:Movie {movieId: toInteger(row.movieId)}) SET m.title = row.title, m.release_year = toInteger(row.release_year);

LOAD CSV WITH HEADERS FROM 'file:///users_node.csv' AS row MERGE (u:User {userId: toInteger(row.userId)});

LOAD CSV WITH HEADERS FROM 'file:///genres_node.csv' AS row MERGE (g:Genre {name: row.genre});

CALL gds.graph.project(
  'movieGraph',
  'Movie',
  {
    SIMILAR_TO: {
      type: 'SIMILAR_TO',
      orientation: 'UNDIRECTED',
      properties: 'weight'
    }
  }
);

CALL gds.louvain.write('movieGraph', {
  relationshipWeightProperty: 'weight',
  writeProperty: 'communityId'
})
YIELD communityCount, modularity;

MATCH (m:Movie)
RETURN m.communityId, count(*) AS size
ORDER BY size DESC;

MATCH (m:Movie)-[:HAS_GENRE]->(g:Genre)
RETURN m.communityId, g.name, count(*) AS freq
ORDER BY m.communityId, freq DESC;

MATCH (u:User)-[r:RATED]->(m:Movie)
RETURN u, r, m
LIMIT 100;
